'use strict';

const test = require('node:test');
const assert = require('node:assert/strict');
const { classifySequence } = require('../src/serialOrder');
const { Replica } = require('../src/replica');

test('rollover successors are classified and applied as forward progress', () => {
  assert.equal(classifySequence(65535, 0).kind, 'forward');
  const replica = new Replica();
  replica.accept({ sequence: 65535, value: 'before' });
  assert.equal(replica.accept({ sequence: 0, value: 'after' }), true);
  assert.equal(replica.current.value, 'after');
});
